import{_ as r,o as t,c as o,ae as e}from"./chunks/framework.C8MNLDzb.js";const u=JSON.parse('{"title":"史部 · 史学典籍","description":"","frontmatter":{},"headers":[],"relativePath":"docs/史部/index.md","filePath":"docs/史部/index.md"}'),n={name:"docs/史部/index.md"};function l(s,a,i,h,d,g){return t(),o("div",null,[...a[0]||(a[0]=[e('<h1 id="史部-·-史学典籍" tabindex="-1">史部 · 史学典籍 <a class="header-anchor" href="#史部-·-史学典籍" aria-label="Permalink to &quot;史部 · 史学典籍&quot;">​</a></h1><blockquote><p>史部收录史学典籍，包括纪传、表志、编年史等，以史为鉴，是中华文明的记录与反思。</p></blockquote><hr><h2 id="《史记》名句" tabindex="-1">《史记》名句 <a class="header-anchor" href="#《史记》名句" aria-label="Permalink to &quot;《史记》名句&quot;">​</a></h2><ol><li><strong>究天人之际，通古今之变，成一家之言。</strong> —— 探究天道与人事的关系，通晓古今变化的规律，形成自己的学说。（《史记·太史公自序》）</li><li><strong>人固有一死，或重于泰山，或轻于鸿毛。</strong> —— 人本来就会死，有的比泰山还重，有的比鸿毛还轻。（《史记·报任安书》）</li><li><strong>智者千虑，必有一失；愚者千虑，必有一得。</strong> —— 聪明人考虑一千次，一定会有一次失误；愚蠢的人考虑一千次，一定会有一次收获。（《史记·淮阴侯列传》）</li><li><strong>项庄舞剑，意在沛公。</strong> —— 项庄表演剑术，真实意图是想杀掉刘邦。（《史记·项羽本纪》）</li><li><strong>大行不顾细谨，大礼不辞小让。</strong> —— 做大事不必顾虑小节，行大礼不必计较小的谦让。（《史记·项羽本纪》）</li><li><strong>运筹帷幄之中，决胜千里之外。</strong> —— 在军帐中运筹谋略，就能决定千里之外战场的胜利。（《史记·高祖本纪》）</li></ol><hr><h2 id="《资治通鉴》名句" tabindex="-1">《资治通鉴》名句 <a class="header-anchor" href="#《资治通鉴》名句" aria-label="Permalink to &quot;《资治通鉴》名句&quot;">​</a></h2><ol><li><strong>鉴于往事，有资于治道。</strong> —— 以往的历史为借鉴，对与治理国家有益。（《资治通鉴》序）</li><li><strong>贤而多财，则损其志；愚而多财，则益其过。</strong> —— 贤能的人财产多了，就会损害他的志向；愚蠢的人财产多了，就会增加他的过失。（《资治通鉴·汉纪》）</li><li><strong>法出而奸令，令下而诈起。</strong> —— 法令一公布，奸诈之事就跟着出现。（《资治通鉴·汉纪》）</li><li><strong>灭六国者，六国也，非秦也。族秦者，秦也，非天下也。</strong> —— 灭掉六国的是六国自己，不是秦国。灭掉秦朝的是秦朝自己，不是天下人。（《资治通鉴·唐纪》杜牧《阿房宫赋》）</li></ol><hr><h2 id="史部典故" tabindex="-1">史部典故 <a class="header-anchor" href="#史部典故" aria-label="Permalink to &quot;史部典故&quot;">​</a></h2><h3 id="破釜沉舟" tabindex="-1">破釜沉舟 <a class="header-anchor" href="#破釜沉舟" aria-label="Permalink to &quot;破釜沉舟&quot;">​</a></h3><p><strong>典故：</strong> 项羽率军渡河后，沉船破釜，每人只带三天口粮，表示不打胜仗决不回来。 <strong>出处：</strong> 《史记·项羽本纪》 <strong>释义：</strong> 比喻下定决心，不留退路。</p><h3 id="背水一战" tabindex="-1">背水一战 <a class="header-anchor" href="#背水一战" aria-label="Permalink to &quot;背水一战&quot;">​</a></h3><p><strong>典故：</strong> 韩信率军进攻赵国，在水边布阵，士兵前临大敌，后无退路，拼死奋战，大获全胜。 <strong>出处：</strong> 《史记·淮阴侯列传》 <strong>释义：</strong> 指在绝境中决一死战。</p><h3 id="纸上谈兵" tabindex="-1">纸上谈兵 <a class="header-anchor" href="#纸上谈兵" aria-label="Permalink to &quot;纸上谈兵&quot;">​</a></h3><p><strong>典故：</strong> 赵括熟读兵书，但不会实际运用，在长平之战中被秦军大败。 <strong>出处：</strong> 《史记·廉颇蔺相如列传》 <strong>释义：</strong> 比喻空谈理论，不能实际解决问题。</p><hr><h2 id="史部代表作者" tabindex="-1">史部代表作者 <a class="header-anchor" href="#史部代表作者" aria-label="Permalink to &quot;史部代表作者&quot;">​</a></h2><h3 id="司马迁-约公元前145年" tabindex="-1">司马迁（约公元前145年-？） <a class="header-anchor" href="#司马迁-约公元前145年" aria-label="Permalink to &quot;司马迁（约公元前145年-？）&quot;">​</a></h3><p>字子长，西汉夏阳人，中国古代伟大的史学家、文学家。继父职任太史令，发愤著书，创作了中国第一部纪传体通史《史记》，被后人尊为&quot;史圣&quot;。</p><h3 id="班固-公元32年-92年" tabindex="-1">班固（公元32年-92年） <a class="header-anchor" href="#班固-公元32年-92年" aria-label="Permalink to &quot;班固（公元32年-92年）&quot;">​</a></h3><p>字孟坚，东汉扶风安陵人。继承父业，耗时二十余年完成《汉书》，是中国第一部纪传体断代史。与司马迁并称&quot;班马&quot;。</p><hr><h2 id="分类说明" tabindex="-1">分类说明 <a class="header-anchor" href="#分类说明" aria-label="Permalink to &quot;分类说明&quot;">​</a></h2><ul><li><strong>纪传体</strong> — 以人物为中心的史书体例，如《史记》《汉书》</li><li><strong>编年体</strong> — 以年代为序的史书，如《资治通鉴》</li><li><strong>纪事本末体</strong> — 以事件为中心的史书体例</li><li><strong>典制体</strong> — 记述制度沿革的史书</li></ul><hr><p><em>本文库由 GuoAgent 运营维护</em></p>',27)])])}const q=r(n,[["render",l]]);export{u as __pageData,q as default};
